// ===== PARSEAR DATOS DE MODIFICACIÓN DESDE CLASSIFICATION =====
// Este webhook recibe modificaciones del workflow de Clasificación
// cuando una reserva en Turitop fue modificada (booking.booking.modified)

const body = $input.first().json.body || $input.first().json;

// El payload viene del Classification v2 con formato:
// { originalBookingId, newBookingId, tourCode, eventDate, newPersonas, eventType, clientName, clientEmail }

const eventType = 'modify'; // Siempre modify para este webhook
const bookingId = body.newBookingId || body.bookingId || `MOD-${Date.now()}`;
const originalBookingId = body.originalBookingId || '';
const tourCode = body.tourCode || '';
const eventDate = body.eventDate || '';
const newPersonas = parseInt(body.newPersonas || 0);
const clienteNombre = body.clientName || '';
const clienteEmail = body.clientEmail || '';
const clienteTelefono = body.clientPhone || '';

// Mapeo de tour codes a product_short_id (reutilizar del mapeo existente)
const TOUR_MAP_REVERSE = {
  'TM': 'P1', 'TT': 'P2', 'WT': 'P3',
  'WTR': 'P4', 'CCATA': 'P5'
};
const productId = TOUR_MAP_REVERSE[tourCode] || tourCode;

// Timestamp
const timestamp = $now.toISO();

return [{
  json: {
    eventType,
    bookingId,
    originalBookingId,
    productId,
    tourCode,
    fecha: eventDate,
    hora: '',
    startISO: '',
    endISO: '',
    adultos: newPersonas,
    ninos: 0,
    totalPersonas: newPersonas,
    clienteNombre,
    clienteEmail,
    clienteTelefono,
    notas: `Modificación desde Clasificación. Original: ${originalBookingId}`,
    timestamp,
    isFromClassification: true
  }
}];

// ===== PARSEAR DATOS DEL WEBHOOK TURITOP =====
const body = $input.first().json.body || $input.first().json;

// --- Tipo de evento ---
const eventType = body.event_type || body.type || 'booking';

// --- IDs ---
const productId = body.product_short_id || body.data?.product_short_id || '';
const bookingId = body.booking_id || body.id || `BK-${Date.now()}`;

// --- Fecha y hora del evento ---
let fecha = '', hora = '', startISO = '', endISO = '';

if (body.data?.events?.[0]) {
  const ev = body.data.events[0];
  const dt = DateTime.fromSeconds(ev.time, { zone: 'Europe/Madrid' });
  fecha = dt.toFormat('yyyy-MM-dd');
  hora = dt.toFormat('HH:mm');
  startISO = ev.time_iso8601 || dt.toISO();
  endISO = dt.plus({ hours: 3 }).toISO();
} else if (body.datetime || body.date) {
  const dt = DateTime.fromISO(body.datetime || body.date, { zone: 'Europe/Madrid' });
  fecha = dt.toFormat('yyyy-MM-dd');
  hora = dt.toFormat('HH:mm');
  startISO = dt.toISO();
  endISO = dt.plus({ hours: 3 }).toISO();
}

// --- Personas ---
const adultos = parseInt(body.adults || body.adultos || 0);
const ninos = parseInt(body.children || body.ninos || 0);
const totalPersonas = parseInt(body.personas || body.pax || body.seats || adultos + ninos || 0);

// --- Tour code (mapeo configurable) ---
// ⚠️ AJUSTAR según los product_short_id reales de Turitop
const TOUR_MAP = {
  'P1': 'TM', 'P2': 'TT', 'P3': 'WT',
  'P4': 'WTR', 'P5': 'CCATA'
};
const tourCode = body.tour_code || TOUR_MAP[productId] || productId;

// --- Es privado? ---
const esPrivado = tourCode.endsWith('P') || (body.is_private === true);

// --- Datos del cliente ---
const clienteNombre = body.customer_name || body.nombre || '';
const clienteEmail = body.customer_email || body.email || '';
const clienteTelefono = body.customer_phone || body.telefono || '';

// --- Notas ---
const notas = body.notes || body.notas || '';

return [{
  json: {
    eventType,
    productId,
    bookingId,
    tourCode,
    esPrivado,
    fecha,
    hora,
    startISO,
    endISO,
    totalPersonas,
    adultos,
    ninos,
    clienteNombre,
    clienteEmail,
    clienteTelefono,
    notas,
    timestamp: DateTime.now().setZone('Europe/Madrid').toISO()
  }
}];

// ===== EVALUAR RESULTADO DEL LOOKUP =====
const items = $input.all();
const parseData = $node["Parsear Datos"].json;

const sheetRow = items[0]?.json || {};
const hasCalendarId = !!sheetRow.calendar_event_id;

return [{
  json: {
    ...parseData,
    calendarEventId: sheetRow.calendar_event_id || '',
    eventoExiste: hasCalendarId,
    currentPersonas: parseInt(sheetRow.total_personas || 0),
    cupoTotal: parseInt(sheetRow.cupo_total || 30),
    cupoPorGuia: parseInt(sheetRow.cupo_por_guia || 15),
    guiaConfirmado: sheetRow.guia_confirmado || '',
    guiasPendientes: sheetRow.guias_pendientes || '',
    statusEvento: sheetRow.status || 'open',
    rowNumber: sheetRow['__rowNumber'] || ''
  }
}];

