// ===== CONSOLIDAR DATOS DE AMBOS CAMINOS =====
// Camino A (TRUE): evento existía → viene de Evaluar Lookup
// Camino B (FALSE): evento nuevo → viene de Registrar Mapa Evento
//   pero el calendarEventId lo tomamos de Crear Evento Calendar

const item = $input.first().json;
const parseData = $node["Parsear Datos"].json;

let calendarEventId = '';
let currentPersonas = 0;
let cupoTotal = 30;
let cupoPorGuia = 15;
let guiaConfirmado = '';
let guiasPendientes = '';

if (item.eventoExiste === true || item.calendarEventId) {
  // Camino A: evento existente, datos completos desde el Sheet
  calendarEventId = item.calendarEventId || '';
  currentPersonas = parseInt(item.currentPersonas || 0);
  cupoTotal = parseInt(item.cupoTotal || 30);
  cupoPorGuia = parseInt(item.cupoPorGuia || 15);
  guiaConfirmado = item.guiaConfirmado || '';
  guiasPendientes = item.guiasPendientes || '';
} else {
  // Camino B: evento recién creado
  // El ID del evento Calendar viene del nodo Crear Evento Calendar
  try {
    calendarEventId = $node["Crear Evento Calendar"].json.id || '';
  } catch(e) {
    calendarEventId = '';
  }
  currentPersonas = 0;
  cupoTotal = 30;
  cupoPorGuia = 15;
  guiaConfirmado = '';
  guiasPendientes = '';
}

return [{
  json: {
    ...parseData,
    calendarEventId,
    currentPersonas,
    cupoTotal,
    cupoPorGuia,
    guiaConfirmado,
    guiasPendientes
  }
}];

// ===== CALCULAR CUPOS, TÍTULO Y VALIDACIONES =====
const parseData = $node["Consolidar Datos"].json;

const eventType = parseData.eventType;
const currentTotal = parseData.currentPersonas;
const newPersonas = parseData.totalPersonas;

// Calcular nuevo total según tipo de evento
let updatedTotal;
switch (eventType) {
  case 'cancel':
    updatedTotal = Math.max(0, currentTotal - newPersonas);
    break;
  case 'modify': {
    // Para modificaciones, restamos reserva anterior y sumamos nueva
    // El originalBookingId viene del Classification workflow
    const originalBookingId = parseData.originalBookingId || '';
    let originalPersonas = parseData.originalPersonas || 0;

    // Si no tenemos originalPersonas, intentamos buscar en Reservas
    if (originalBookingId && !originalPersonas) {
      // En producción, aquí haríamos lookup en Google Sheets
      // Por ahora usamos la diferencia directa si está disponible
      originalPersonas = parseData.originalPersonas || 0;
    }

    // Lógica: restar reserva anterior, sumar nueva
    updatedTotal = Math.max(0, currentTotal - originalPersonas + newPersonas);
    break;
  }
  default: // booking
    updatedTotal = currentTotal + newPersonas;
}

const cupoTotal = parseData.cupoTotal;
const cupoPorGuia = parseData.cupoPorGuia;
const guiaConfirmado = parseData.guiaConfirmado;
const guiasPendientes = parseData.guiasPendientes;

// Guías
const numGuiasConfirmados = guiaConfirmado ? 1 : 0;
const listaPendientes = guiasPendientes ? guiasPendientes.split(',').map(g => g.trim()) : [];
const numGuiasTotal = numGuiasConfirmados + listaPendientes.length;
const guiasNecesarios = Math.ceil(updatedTotal / cupoPorGuia);

// Flags de validación
const cupoTotalAlcanzado = updatedTotal >= cupoTotal;
const cupoGuiaSuperado = updatedTotal > (cupoPorGuia * Math.max(numGuiasConfirmados, 1));
const hayPendientes = listaPendientes.length > 0;
const necesitaMasGuias = guiasNecesarios > numGuiasTotal;

// Título del evento en Calendar
let nuevoTitulo = `${parseData.tourCode} ${updatedTotal}`;
if (guiaConfirmado) nuevoTitulo += ` ${guiaConfirmado}`;
if (hayPendientes) nuevoTitulo += ` (${guiasPendientes})`;

// Descripción detallada
const descripcion = [
  `📊 Personas: ${updatedTotal}/${cupoTotal}`,
  `👤 Guía confirmado: ${guiaConfirmado || 'Sin asignar'}`,
  `⏳ Guías pendientes: ${guiasPendientes || 'Ninguno'}`,
  `🔢 Guías necesarios: ${guiasNecesarios}`,
  `📦 Producto Turitop: ${parseData.productId}`,
  `---`,
  `Última reserva: ${parseData.clienteNombre} (${newPersonas} pax)`,
  `Actualizado: ${parseData.timestamp}`
].join('\n');

return [{
  json: {
    ...parseData,
    updatedTotal,
    cupoTotalAlcanzado,
    cupoGuiaSuperado,
    necesitaMasGuias,
    hayPendientes,
    guiasNecesarios,
    nuevoTitulo,
    descripcion,
    listaPendientes
  }
}];
